const input = $input.first().json;
const conditions = [`phone_number = '${input.phone_number}'`];

if (input.categoria && input.categoria !== '' && input.categoria !== 'null') {
  conditions.push(`categoria = '${input.categoria}'`);
}
if (input.descripcion && input.descripcion !== '' && input.descripcion !== 'null') {
  conditions.push(`descripcion ILIKE '%${input.descripcion.replace(/'/g, "''")}%'`);
}
if (input.fecha_desde && input.fecha_desde !== '' && input.fecha_desde !== 'null') {
  conditions.push(`fecha >= '${input.fecha_desde}'`);
}
if (input.fecha_hasta && input.fecha_hasta !== '' && input.fecha_hasta !== 'null') {
  conditions.push(`fecha <= '${input.fecha_hasta}'::date + INTERVAL '1 day'`);
}

const query = `SELECT id, monto, categoria, descripcion, fecha FROM gastos WHERE ${conditions.join(' AND ')} ORDER BY fecha DESC LIMIT 20`;
return [{ json: { query } }];

const items = $input.all();
const gastos = items.filter(item => item.json.id != null);

if (gastos.length === 0) {
  return [{ json: { output: 'No se encontraron gastos con esos filtros.' } }];
}

const total = gastos.reduce((sum, item) => sum + parseFloat(item.json.monto), 0);

const lines = gastos.map((item, i) => {
  const fecha = new Date(item.json.fecha).toLocaleDateString('es-AR');
  const monto = parseFloat(item.json.monto).toFixed(2);
  const desc = item.json.descripcion ? ` \u2014 ${item.json.descripcion}` : '';
  return `${i + 1}. $${monto} \u2014 ${item.json.categoria}${desc} (${fecha}) [ID #${item.json.id}]`;
});

const output = `Encontrados ${gastos.length} gastos (total: $${total.toFixed(2)}):\n${lines.join('\n')}`;
return [{ json: { output } }];
